mapper.select:
select exists (
    select 1
    from tbl_conversation_member_rel
    where conversation_id = #{conversationId}
      and (sender_id = #{memberId} or invited_id = #{memberId})
)

mapper.update:
update tbl_conversation_setting
set alias = #{alias}, updated_datetime = now()
where conversation_id = #{conversationId} and member_id = #{memberId}

update tbl_conversation_setting
set is_screen_blocked = #{blocked}, updated_datetime = now()
where conversation_id = #{conversationId} and member_id = #{memberId}

mapper.select:
select coalesce(is_screen_blocked, false)
from tbl_conversation_setting
where conversation_id = #{conversationId} and member_id = #{memberId}

mapper.update:
update tbl_conversation_setting
set is_deleted = true,
    is_muted = false,
    alias = null,
    is_pinned = false,
    deleted_after_message_id = (
        select max(id) from tbl_message where conversation_id = #{conversationId}
    ),
    updated_datetime = now()
where conversation_id = #{conversationId} and member_id = #{memberId}

update tbl_conversation_setting
set blocked_after_message_id = #{messageId}, updated_datetime = now()
where conversation_id = #{conversationId} and member_id = #{memberId}

update tbl_conversation_setting
set block_released_message_id = #{messageId}, updated_datetime = now()
where conversation_id = #{conversationId} and member_id = #{memberId}

update tbl_conversation_setting
set disappear_message = #{setting},
    disappear_activated_at = case
        when #{setting} in ('none', '없음') then null
        else now()
    end,
    updated_datetime = now()
where conversation_id = #{conversationId} and member_id = #{memberId}
